import { create } from 'zustand'

export const useProgressStore = create((set) => ({
    currentBar: null,
    progressQueue: [],
    bars: [],
    nextId: null,
    addBar: () => set((state) => {
        const id = crypto.randomUUID();
        return {
            bars: [...state.bars, { id, active: false }],
            progressQueue: [...state.progressQueue, id]
        }
    }),
    setCurrentBar: (id) => set((state) => ({
        currentBar: id
    })),
    getNextBar: () => set((state) => ({
        nextId: state.progressQueue.shift()
    })),
    updateBars: (id, isActive) => set((state) => ({
        bars: state.bars.map((b) =>
            b.id === nextId ? { ...b, active: isActive } : b
        )
    }))
}))
